create extension if not exists pgcrypto with schema extensions;
do $$ begin create type public.calendar_item_type as enum ('event','task','deadline','preparation'); exception when duplicate_object then null; end $$;
do $$ begin create type public.flexibility_mode as enum ('fixed','protected','flexible'); exception when duplicate_object then null; end $$;
do $$ begin create type public.calendar_item_status as enum ('scheduled','in_progress','completed','cancelled'); exception when duplicate_object then null; end $$;
do $$ begin create type public.proposal_status as enum ('draft','approved','rejected','stale'); exception when duplicate_object then null; end $$;
create table if not exists public.profiles(id uuid primary key references auth.users(id) on delete cascade,email text not null,full_name text not null,username text not null unique,avatar_url text,timezone text not null default 'Asia/Manila',active_start time not null default '07:00',active_end time not null default '22:30',onboarding_completed boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),constraint profiles_username_format check(username~'^[a-z0-9_]{3,32}$'));
create table if not exists public.schedule_proposals(id uuid primary key default gen_random_uuid(),user_id uuid not null references public.profiles(id) on delete cascade,proposal_type text not null check(proposal_type in('creation','repair')),status public.proposal_status not null default 'draft',base_schedule_version integer not null default 1,payload jsonb not null default '{}'::jsonb,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.calendar_items(id uuid primary key default gen_random_uuid(),user_id uuid not null references public.profiles(id) on delete cascade,item_type public.calendar_item_type not null,title text not null check(char_length(title) between 1 and 160),description text,start_at timestamptz,end_at timestamptz,due_at timestamptz,timezone text not null default 'Asia/Manila',priority smallint not null default 3 check(priority between 1 and 5),flexibility public.flexibility_mode not null default 'flexible',earliest_start timestamptz,latest_end timestamptz,normal_duration_minutes integer,minimum_duration_minutes integer,minimum_chunk_minutes integer,can_shorten boolean not null default false,can_split boolean not null default false,can_skip boolean not null default false,location_label text,recurrence_rule text,related_deadline_id uuid references public.calendar_items(id) on delete set null,status public.calendar_item_status not null default 'scheduled',version integer not null default 1,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),constraint calendar_items_range check(start_at is null or end_at is null or end_at>start_at),constraint calendar_items_shape check((item_type='deadline' and due_at is not null and start_at is null and end_at is null)or(item_type<>'deadline' and start_at is not null and end_at is not null)));
create table if not exists public.preferences(id uuid primary key default gen_random_uuid(),user_id uuid not null references public.profiles(id) on delete cascade,category text not null,default_duration_minutes integer,flexibility public.flexibility_mode,can_shorten boolean not null default false,can_split boolean not null default false,can_skip boolean not null default false,source text not null default 'explicit' check(source='explicit'),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(user_id,category));
create table if not exists public.audit_events(id bigint generated by default as identity primary key,user_id uuid not null references public.profiles(id) on delete cascade,action text not null,entity_type text not null,entity_id uuid,metadata jsonb not null default '{}'::jsonb,created_at timestamptz not null default now(),constraint audit_no_private_payload check(not(metadata ?| array['raw_audio','exact_coordinates','service_role_key','access_token'])));
create or replace function public.set_updated_at()returns trigger language plpgsql security invoker set search_path='' as $$ begin new.updated_at=now();return new;end $$;
create or replace function public.handle_new_user()returns trigger language plpgsql security definer set search_path='' as $$ declare u text;begin u:=lower(regexp_replace(coalesce(new.raw_user_meta_data->>'username',split_part(new.email,'@',1)),'[^a-zA-Z0-9_]','','g'));if char_length(u)<3 then u:='kairos_user';end if;u:=left(u,23)||'_'||left(replace(new.id::text,'-',''),8);insert into public.profiles(id,email,full_name,username)values(new.id,coalesce(new.email,''),coalesce(nullif(new.raw_user_meta_data->>'full_name',''),split_part(coalesce(new.email,'Kairos user'),'@',1)),u)on conflict(id)do nothing;return new;end $$;
drop trigger if exists on_auth_user_created on auth.users;create trigger on_auth_user_created after insert on auth.users for each row execute function public.handle_new_user();
do $$ declare t text;begin foreach t in array array['profiles','calendar_items','preferences','schedule_proposals','audit_events'] loop execute format('alter table public.%I enable row level security',t);execute format('alter table public.%I force row level security',t);end loop;end $$;
create policy profiles_select_own on public.profiles for select to authenticated using(id=(select auth.uid()));create policy profiles_update_own on public.profiles for update to authenticated using(id=(select auth.uid()))with check(id=(select auth.uid()));
create policy items_select_own on public.calendar_items for select to authenticated using(user_id=(select auth.uid()));create policy items_insert_own on public.calendar_items for insert to authenticated with check(user_id=(select auth.uid()));create policy items_update_own on public.calendar_items for update to authenticated using(user_id=(select auth.uid()))with check(user_id=(select auth.uid()));create policy items_delete_own on public.calendar_items for delete to authenticated using(user_id=(select auth.uid()));
create policy prefs_select_own on public.preferences for select to authenticated using(user_id=(select auth.uid()));create policy prefs_insert_own on public.preferences for insert to authenticated with check(user_id=(select auth.uid()));create policy prefs_update_own on public.preferences for update to authenticated using(user_id=(select auth.uid()))with check(user_id=(select auth.uid()));create policy prefs_delete_own on public.preferences for delete to authenticated using(user_id=(select auth.uid()));
create policy proposals_select_own on public.schedule_proposals for select to authenticated using(user_id=(select auth.uid()));create policy proposals_insert_own on public.schedule_proposals for insert to authenticated with check(user_id=(select auth.uid()));create policy proposals_update_own on public.schedule_proposals for update to authenticated using(user_id=(select auth.uid()))with check(user_id=(select auth.uid()));create policy proposals_delete_own on public.schedule_proposals for delete to authenticated using(user_id=(select auth.uid()));
create policy audit_select_own on public.audit_events for select to authenticated using(user_id=(select auth.uid()));create policy audit_insert_own on public.audit_events for insert to authenticated with check(user_id=(select auth.uid()));
revoke all on public.profiles,public.calendar_items,public.preferences,public.schedule_proposals,public.audit_events from anon;grant select,update on public.profiles to authenticated;grant select,insert,update,delete on public.calendar_items,public.preferences,public.schedule_proposals to authenticated;grant select,insert on public.audit_events to authenticated;
